#include<bits/stdc++.h>
using namespace std;
#define next next0
#define int long long

const int N = 1e6 + 7;

string s;
int next[N];

signed main()
{
    int n;
    cin >> n;
    cin >> s;
    s = '&' + s;
    int j = 0, ans = 0;
    for(int i = 2; i <= n; i++)
    {
        while(j && s[j + 1] != s[i]) j = next[j];
        if(s[j + 1] == s[i]) ++j;
        next[i] = j;
    }
    j = 2;
    for(int i = 2; i <= n; i++)
    {
        j = i;
        while(next[j]) j = next[j];
        if(next[i]) next[i] = j;
        ans += i - j;
    }
    cout << ans;
}
